formulas.expression:
IF(UPPER({!followUpInspectionTypeSelected}) = "INSPECTION UPDATE", "Inspection Update",

   IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "ROUTINE", "Routine Follow-up",

      IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "IN-DEPTH", "In-Depth Follow-up",

         IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "PRE-LICENSING", "Pre-licensing Follow-up",

            IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "COMPLAINT", "Complaint Follow-up",

               IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "REQUEST", "Request Follow-up",

                  IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "INITIAL", "Initial Follow-up",

                     IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "INCIDENT", "Incident Follow-up",
                        ""
                       )
                    )
                 )
              )
           )
        )
     )
  )

IF(UPPER({!inspectionFollowUpType}) = "INSPECTION UPDATE", "Inspection Update",

  IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "ROUTINE", "Routine Follow-up",

    IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "IN-DEPTH", "In-Depth Follow-up",

      IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "PRE-LICENSING", "Pre-licensing Follow-up",

        IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "COMPLAINT", "Complaint Follow-up",

          IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "REQUEST", "Request Follow-up",

            IF(UPPER({!Get_Insp_Record.VisitType.Name}) = "INITIAL", "Initial Follow-up",
              ""
            )
          )
        )
      )
    )
  )
)
